import { RotateCcw } from "lucide-react";

interface AccessibilityResetButtonProps {
  onReset: () => void;
  disabled: boolean;
}

function AccessibilityResetButtonInner({ onReset, disabled }: AccessibilityResetButtonProps) {
  return (
    <button
      type="button"
      onClick={onReset}
      disabled={disabled}
      className="a11y-widget-reset-btn"
    >
      <RotateCcw className="a11y-widget-reset-icon" aria-hidden="true" />
      Reset All Settings
    </button>
  );
}

AccessibilityResetButtonInner.displayName = "AccessibilityResetButton";
export const AccessibilityResetButton = AccessibilityResetButtonInner;
