export interface AccessibilityFeatureFlags {
  contrast?: boolean;
  textSize?: boolean;
  textSpacing?: boolean;
  lineHeight?: boolean;
  textAlign?: boolean;
  highlightLinks?: boolean;
  pauseAnimations?: boolean;
  hideImages?: boolean;
  cursorEnhancement?: boolean;
  dyslexiaFont?: boolean;
  saturation?: boolean;
  readingGuide?: boolean;
}

export interface AccessibilityWidgetConfig {
  position?: "bottom-left" | "bottom-right" | "top-left" | "top-right";
  brandColors?: {
    primary?: string;
    secondary?: string;
    accent?: string;
  };
  launcher?: {
    size?: "sm" | "md" | "lg";
    tooltip?: string;
    zIndex?: number;
  };
  panel?: {
    title?: string;
    subtitle?: string;
    footerNote?: string;
  };
  features?: AccessibilityFeatureFlags;
  storageKey?: string;
}

export interface ResolvedConfig {
  position: "bottom-left" | "bottom-right" | "top-left" | "top-right";
  brandColors: {
    primary: string;
    secondary: string;
    accent: string;
  };
  launcher: {
    size: "sm" | "md" | "lg";
    tooltip: string;
    zIndex: number;
  };
  panel: {
    title: string;
    subtitle: string;
    footerNote: string;
  };
  features: Required<AccessibilityFeatureFlags>;
  storageKey: string;
}

const DEFAULT_CONFIG: ResolvedConfig = {
  position: "bottom-left",
  brandColors: {
    primary: "#0d9488",
    secondary: "#1e3a5f",
    accent: "#f59e0b",
  },
  launcher: {
    size: "md",
    tooltip: "Accessibility Options",
    zIndex: 9999,
  },
  panel: {
    title: "Accessibility Options",
    subtitle: "Customize the site experience for readability, visibility, and comfort.",
    footerNote: "This menu helps personalize your browsing experience.",
  },
  features: {
    contrast: true,
    textSize: true,
    textSpacing: true,
    lineHeight: true,
    textAlign: true,
    highlightLinks: true,
    pauseAnimations: true,
    hideImages: true,
    cursorEnhancement: true,
    dyslexiaFont: true,
    saturation: true,
    readingGuide: true,
  },
  storageKey: "a11y-settings",
};

export function resolveConfig(userConfig?: AccessibilityWidgetConfig): ResolvedConfig {
  if (!userConfig) return { ...DEFAULT_CONFIG };

  return {
    position: userConfig.position ?? DEFAULT_CONFIG.position,
    brandColors: {
      ...DEFAULT_CONFIG.brandColors,
      ...userConfig.brandColors,
    },
    launcher: {
      ...DEFAULT_CONFIG.launcher,
      ...userConfig.launcher,
    },
    panel: {
      ...DEFAULT_CONFIG.panel,
      ...userConfig.panel,
    },
    features: {
      ...DEFAULT_CONFIG.features,
      ...userConfig.features,
    },
    storageKey: userConfig.storageKey ?? DEFAULT_CONFIG.storageKey,
  };
}
