import type { ReactNode } from "react";

interface AccessibilitySectionProps {
  title: string;
  children: ReactNode;
}

function AccessibilitySectionInner({ title, children }: AccessibilitySectionProps) {
  return (
    <div role="group" aria-labelledby={`a11y-section-${title.replace(/\s+/g, "-").toLowerCase()}`}>
      <h3
        id={`a11y-section-${title.replace(/\s+/g, "-").toLowerCase()}`}
        className="a11y-widget-section-title"
      >
        {title}
      </h3>
      <div className="a11y-widget-section-content">{children}</div>
    </div>
  );
}

AccessibilitySectionInner.displayName = "AccessibilitySection";
export const AccessibilitySection = AccessibilitySectionInner;
