import type { ReactNode } from "react";
import { Minus, Plus } from "lucide-react";
import { cn } from "../lib/utils";

interface AccessibilityRangeControlProps {
  icon: ReactNode;
  label: string;
  description: string;
  value: number;
  min: number;
  max: number;
  onChange: (value: number) => void;
}

function AccessibilityRangeControlInner({
  icon,
  label,
  description,
  value,
  min,
  max,
  onChange,
}: AccessibilityRangeControlProps) {
  return (
    <div
      className={cn(
        "a11y-widget-range-card",
        value > min && "a11y-widget-range-card--active"
      )}
      role="group"
      aria-label={label}
    >
      <div
        className={cn(
          "a11y-widget-toggle-icon",
          value > min && "a11y-widget-toggle-icon--active"
        )}
      >
        {icon}
      </div>
      <div className="a11y-widget-toggle-text">
        <p className={cn("a11y-widget-toggle-label", value > min && "a11y-widget-toggle-label--active")}>
          {label}
        </p>
        <p className="a11y-widget-toggle-desc">{description}</p>
        <div className="a11y-widget-range-controls">
          <button
            type="button"
            onClick={() => onChange(Math.max(min, value - 1))}
            disabled={value <= min}
            aria-label={`Decrease ${label}`}
            className="a11y-widget-range-btn"
          >
            <Minus className="a11y-widget-range-btn-icon" aria-hidden="true" />
          </button>
          <div className="a11y-widget-range-track" aria-hidden="true">
            {Array.from({ length: max - min + 1 }).map((_, i) => (
              <div
                key={i}
                className={cn(
                  "a11y-widget-range-step",
                  i <= value - min - 1 && "a11y-widget-range-step--filled"
                )}
              />
            ))}
          </div>
          <span className="a11y-widget-sr-only" aria-live="polite">
            {label}: level {value} of {max}
          </span>
          <button
            type="button"
            onClick={() => onChange(Math.min(max, value + 1))}
            disabled={value >= max}
            aria-label={`Increase ${label}`}
            className="a11y-widget-range-btn"
          >
            <Plus className="a11y-widget-range-btn-icon" aria-hidden="true" />
          </button>
        </div>
      </div>
    </div>
  );
}

AccessibilityRangeControlInner.displayName = "AccessibilityRangeControl";
export const AccessibilityRangeControl = AccessibilityRangeControlInner;
