import { useContext } from "react";
import { AccessibilityContext, type AccessibilityContextType } from "../context/AccessibilityContext";

export function useAccessibility(): AccessibilityContextType {
  const context = useContext(AccessibilityContext);
  if (!context) {
    throw new Error(
      "useAccessibility must be used within an <AccessibilityProvider>. " +
      "Wrap your component tree with <AccessibilityProvider> from @wolfconsulting/accessibility-widget."
    );
  }
  return context;
}
