import { createContext, useState, useEffect, useCallback, useRef, useMemo } from "react";
import type { ReactNode } from "react";
import {
  type AccessibilitySettings,
  defaultSettings,
  loadSettings,
  saveSettings,
  clearSettings,
  applySettingsToDOM,
  isDefault,
  getActiveCount,
} from "../lib/accessibility";
import {
  type AccessibilityWidgetConfig,
  type ResolvedConfig,
  resolveConfig,
} from "../lib/config";

export interface AccessibilityContextType {
  settings: AccessibilitySettings;
  updateSetting: <K extends keyof AccessibilitySettings>(
    key: K,
    value: AccessibilitySettings[K]
  ) => void;
  resetAll: () => void;
  isAllDefault: boolean;
  activeCount: number;
  config: ResolvedConfig;
}

export const AccessibilityContext = createContext<AccessibilityContextType | null>(null);

interface AccessibilityProviderProps {
  children: ReactNode;
  config?: AccessibilityWidgetConfig;
}

function AccessibilityProviderInner({ children, config: userConfig }: AccessibilityProviderProps) {
  const resolvedConfig = useMemo(() => resolveConfig(userConfig), [userConfig]);
  const [settings, setSettings] = useState<AccessibilitySettings>(defaultSettings);
  const initialized = useRef(false);

  useEffect(() => {
    const loaded = loadSettings(resolvedConfig.storageKey);
    setSettings(loaded);
    applySettingsToDOM(loaded);
    initialized.current = true;
  }, [resolvedConfig.storageKey]);

  const updateSetting = useCallback(
    <K extends keyof AccessibilitySettings>(key: K, value: AccessibilitySettings[K]) => {
      setSettings((prev) => {
        const next = { ...prev, [key]: value };

        if (key === "highContrast" && value && next.softContrast) {
          next.softContrast = false;
        }
        if (key === "softContrast" && value && next.highContrast) {
          next.highContrast = false;
        }

        saveSettings(resolvedConfig.storageKey, next);
        applySettingsToDOM(next);
        return next;
      });
    },
    [resolvedConfig.storageKey]
  );

  const resetAll = useCallback(() => {
    setSettings({ ...defaultSettings });
    clearSettings(resolvedConfig.storageKey);
    applySettingsToDOM(defaultSettings);
  }, [resolvedConfig.storageKey]);

  const contextValue = useMemo<AccessibilityContextType>(
    () => ({
      settings,
      updateSetting,
      resetAll,
      isAllDefault: isDefault(settings),
      activeCount: getActiveCount(settings),
      config: resolvedConfig,
    }),
    [settings, updateSetting, resetAll, resolvedConfig]
  );

  return (
    <AccessibilityContext.Provider value={contextValue}>
      {children}
    </AccessibilityContext.Provider>
  );
}

AccessibilityProviderInner.displayName = "AccessibilityProvider";

export const AccessibilityProvider = AccessibilityProviderInner;
