import type { ReactNode } from "react";
import { cn } from "../lib/utils";

interface AccessibilityToggleCardProps {
  icon: ReactNode;
  label: string;
  description: string;
  active: boolean;
  onToggle: () => void;
}

function AccessibilityToggleCardInner({
  icon,
  label,
  description,
  active,
  onToggle,
}: AccessibilityToggleCardProps) {
  return (
    <button
      type="button"
      role="switch"
      aria-checked={active}
      aria-label={label}
      onClick={onToggle}
      className={cn(
        "a11y-widget-toggle-card",
        active && "a11y-widget-toggle-card--active"
      )}
    >
      <div
        className={cn(
          "a11y-widget-toggle-icon",
          active && "a11y-widget-toggle-icon--active"
        )}
      >
        {icon}
      </div>
      <div className="a11y-widget-toggle-text">
        <p className={cn("a11y-widget-toggle-label", active && "a11y-widget-toggle-label--active")}>
          {label}
        </p>
        <p className="a11y-widget-toggle-desc">{description}</p>
      </div>
      <div className={cn("a11y-widget-switch", active && "a11y-widget-switch--active")}>
        <div className={cn("a11y-widget-switch-knob", active && "a11y-widget-switch-knob--active")} />
      </div>
    </button>
  );
}

AccessibilityToggleCardInner.displayName = "AccessibilityToggleCard";
export const AccessibilityToggleCard = AccessibilityToggleCardInner;
